class PasswordVaultManager {
    
    static let shared = PasswordVaultManager()
    
    private let hashingService = PasswordHashingService.shared
    private let storageService = SecureStorageService.shared
    
    private let masterPasswordKey = "master_password_hash"
    private let credentialPrefix = "credential_"
    private let credentialListKey = "credential_list"
    
    private init() {}
    
    // MARK: - Master Password Management
    
    var isMasterPasswordSet: Bool {
        return storageService.loadString(key: masterPasswordKey) != nil
    }
    
    func setMasterPassword(_ password: String) -> Bool {
        guard let hash = hashingService.createPasswordHash(password) else { return false }
        return storageService.saveString(key: masterPasswordKey, value: hash)
    }
    
    func verifyMasterPassword(_ password: String) -> Bool {
        guard let storedHash = storageService.loadString(key: masterPasswordKey) else { return false }
        return hashingService.verifyPassword(password, againstHash: storedHash)
    }
    
    func changeMasterPassword(oldPassword: String, newPassword: String) -> Bool {
        guard verifyMasterPassword(oldPassword) else { return false }
        return setMasterPassword(newPassword)
    }
    
    // MARK: - Credential Storage
    
    func saveCredential(identifier: String, username: String, password: String) -> Bool {
        let credentialData: [String: String] = [
            "username": username,
            "password": password,
            "created": ISO8601DateFormatter().string(from: Date())
        ]
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: credentialData) else {
            return false
        }
        
        let key = credentialPrefix + identifier
        let saved = storageService.save(key: key, data: jsonData)
        
        if saved {
            addToCredentialList(identifier)
        }
        
        return saved
    }
    
    func loadCredential(identifier: String) -> (username: String, password: String)? {
        let key = credentialPrefix + identifier
        guard let data = storageService.load(key: key),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: String],
              let username = json["username"],
              let password = json["password"] else {
            return nil
        }
        return (username, password)
    }
    
    func deleteCredential(identifier: String) -> Bool {
        let key = credentialPrefix + identifier
        let deleted = storageService.delete(key: key)
        if deleted {
            removeFromCredentialList(identifier)
        }
        return deleted
    }
    
    func allCredentialIdentifiers() -> [String] {
        guard let data = storageService.load(key: credentialListKey),
              let list = try? JSONSerialization.jsonObject(with: data) as? [String] else {
            return []
        }
        return list
    }
    
    private func addToCredentialList(_ identifier: String) {
        var list = allCredentialIdentifiers()
        if !list.contains(identifier) {
            list.append(identifier)
        }
        if let data = try? JSONSerialization.data(withJSONObject: list) {
            storageService.save(key: credentialListKey, data: data)
        }
    }
    
    private func removeFromCredentialList(_ identifier: String) {
        var list = allCredentialIdentifiers()
        list.removeAll { $0 == identifier }
        if let data = try? JSONSerialization.data(withJSONObject: list) {
            storageService.save(key: credentialListKey, data: data)
        }
    }
    
    // Reset everything
    func resetVault() {
        let identifiers = allCredentialIdentifiers()
        for id in identifiers {
            storageService.delete(key: credentialPrefix + id)
        }
        storageService.delete(key: credentialListKey)
        storageService.delete(key: masterPasswordKey)
    }
}

